 851→    {
 852→        const q7_t *pA = ker_weight;
 853→        int i;
 854→
 855→        for (i = 0; i < out_tensor_ch; i++)
 856→        {
 857→            long sum = 0;
 858→            q7_t *pB = (q7_t*)in_tmp_buf;
 859→
 860→            /* basically each time it process 8 entries */
 861→            uint16_t  colCnt = 3 * ker_dim * ker_dim >> 3;
 862→
 863→            while (colCnt)
 864→            {
 865→                long inA1, inB1;
