311→        NDS_VEC_VLE32_V(NDS_VEC_V8, bias);
312→
313→        /* Set e8/M2 once for all vqmacc accumulation (e8*e8->e32, M2 input, M8 acc) */
314→        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
